import { notFound } from 'next/navigation'
import Link from 'next/link'
import Script from 'next/script'
import { jsonLdForTool } from '../../../utils/seo'
import AdPlaceholder from '../../../components/AdPlaceholder'
import { tools } from '../../../data/tools'

type Props = { params: { slug: string } }

export async function generateMetadata({ params }: Props) {
  const tool = tools.find((item) => item.slug === params.slug)
  if (!tool) return { title: 'Tool not found' }
  return { title: `${tool.title} - ToolHub India`, description: tool.description }
}

export async function generateStaticParams() {
  return tools.map((tool) => ({ slug: tool.slug }))
}

export default function ToolPage({ params }: Props) {
  const tool = tools.find((item) => item.slug === params.slug)
  if (!tool) return notFound()

  const host = process.env.NEXT_PUBLIC_SITE_URL || 'https://example.com'
  const canonical = `${host}/tools/${params.slug}`
  const ld = jsonLdForTool({ title: tool.title, description: tool.description, url: canonical })
  const relatedTools = tools.filter((item) => item.category === tool.category && item.slug !== tool.slug).slice(0, 3)

  return (
    <main className="container mx-auto p-4">
      <Script id="ld+json" type="application/ld+json">{JSON.stringify(ld)}</Script>

      <nav className="text-sm text-slate-500 mb-4">
        <Link href="/">Home</Link> / <Link href="/tools">Tools</Link> / <span>{tool.title}</span>
      </nav>

      <h1 className="text-2xl font-bold">{tool.title}</h1>
      <p className="text-slate-600 dark:text-slate-300">{tool.description}</p>

      <section className="mt-6">
        <div className="p-4 border rounded">
          <p>Tool UI will be implemented here per tool.</p>
        </div>
      </section>

      <AdPlaceholder />

      <section className="mt-8">
        <h2 className="font-semibold">More {tool.category} Tools</h2>
        <ul className="mt-2 space-y-2">
          {relatedTools.length > 0 ? (
            relatedTools.map((related) => (
              <li key={related.slug}>
                <Link href={`/tools/${related.slug}`} className="text-blue-600 hover:underline">
                  {related.title}
                </Link>
              </li>
            ))
          ) : (
            <li className="text-slate-500">No additional tools in this category yet.</li>
          )}
        </ul>
      </section>
    </main>
  )
}
